707	
708	    // addNewTransaction must update state for all ancestors of a given transaction,
709	    // to track size/count of descendant transactions.  First version of
710	    // addNewTransaction can be used to have it call CalculateMemPoolAncestors(), and
711	    // then invoke the second version.
712	    // Note that addNewTransaction is ONLY called (via Apply()) from ATMP
713	    // outside of tests and any other callers may break wallet's in-mempool
714	    // tracking (due to lack of CValidationInterface::TransactionAddedToMempool
715	    // callbacks).
716	    void addNewTransaction(CTxMemPool::txiter it) EXCLUSIVE_LOCKS_REQUIRED(cs);
717	public:
718	    void StartBlockBuilding() const EXCLUSIVE_LOCKS_REQUIRED(cs) { assert(!m_builder); m_builder = m_txgraph->GetBlockBuilder(); }
719	    FeePerWeight GetBlockBuilderChunk(std::vector<CTxMemPoolEntry::CTxMemPoolEntryRef>& entries) const EXCLUSIVE_LOCKS_REQUIRED(cs)
720	    {
721	        if (!m_builder) { return {}; }
722	
723	        auto res = m_builder->GetCurrentChunk();
724	        if (!res) { return {}; }
725	
726	        auto [chunk_entries, chunk_feerate] = *res;
727	        for (TxGraph::Ref* ref : chunk_entries) {
728	            entries.emplace_back(static_cast<const CTxMemPoolEntry&>(*ref));
729	        }
730	        return chunk_feerate;
731	    }
732	    void IncludeBuilderChunk() const EXCLUSIVE_LOCKS_REQUIRED(cs) { m_builder->Include(); }
733	    void SkipBuilderChunk() const EXCLUSIVE_LOCKS_REQUIRED(cs) { m_builder->Skip(); }
734	    void StopBlockBuilding() const EXCLUSIVE_LOCKS_REQUIRED(cs) { m_builder.reset(); }
