4936	bool Chainstate::LoadGenesisBlock()
4937	{
4938	    LOCK(cs_main);
4939	
4940	    const CChainParams& params{m_chainman.GetParams()};
4941	
4942	    // Check whether we're already initialized by checking for genesis in
4943	    // m_blockman.m_block_index. Note that we can't use m_chain here, since it is
4944	    // set based on the coins db, not the block index db, which is the only
4945	    // thing loaded at this point.
4946	    if (m_blockman.m_block_index.contains(params.GenesisBlock().GetHash()))
4947	        return true;
4948	
4949	    try {

5150	
5151	    // During a reindex, we read the genesis block and call CheckBlockIndex before ActivateBestChain,
5152	    // so we have the genesis block in m_blockman.m_block_index but no active chain. (A few of the
5153	    // tests when iterating the block tree require that m_chain has been initialized.)
5154	    if (ActiveChain().Height() < 0) {
5155	        assert(m_blockman.m_block_index.size() <= 1);
5156	        return;
5157	    }
5158	
5159	    // Build forward-pointing data structure for the entire block tree.
5160	    // For performance reasons, indexes of the best header chain are stored in a vector (within CChain).
5161	    // All remaining blocks are stored in a multimap.
5162	    // The best header chain can differ from the active chain: E.g. its entries may belong to blocks that
5163	    // are not yet validated.
5164	    CChain best_hdr_chain;
5165	    assert(m_best_header);
5166	    assert(!(m_best_header->nStatus & BLOCK_FAILED_VALID));
5167	    best_hdr_chain.SetTip(*m_best_header);
5168	
5169	    std::multimap<const CBlockIndex*, const CBlockIndex*> forward;
5170	    for (auto& [_, block_index] : m_blockman.m_block_index) {
5171	        // Only save indexes in forward that are not part of the best header chain.
5172	        if (!best_hdr_chain.Contains(block_index)) {
5173	            // Only genesis, which must be part of the best header chain, can have a nullptr parent.
5174	            assert(block_index.pprev);
5175	            forward.emplace(block_index.pprev, &block_index);
5176	        }
5177	    }
5178	    assert(forward.size() + best_hdr_chain.Height() + 1 == m_blockman.m_block_index.size());
5179	
5180	    const CBlockIndex* pindex = best_hdr_chain[0];
5181	    assert(pindex);
