2231	
2232	        // restore inputs
2233	        if (i > 0) { // not coinbases
2234	            CTxUndo &txundo = blockUndo.vtxundo[i-1];
2235	            if (txundo.vprevout.size() != tx.vin.size()) {
2236	                LogError("DisconnectBlock(): transaction and undo data inconsistent\n");
