2238	            }
2239	            for (unsigned int j = tx.vin.size(); j > 0;) {
2240	                --j;
2241	                const COutPoint& out = tx.vin[j].prevout;
2242	                int res = ApplyTxInUndo(std::move(txundo.vprevout[j]), view, out);
