1931	void PeerManagerImpl::MaybePunishNodeForBlock(NodeId nodeid, const BlockValidationState& state,
1932	                                              bool via_compact_block, const std::string& message)
1933	{
1934	    PeerRef peer{GetPeerRef(nodeid)};
1935	    switch (state.GetResult()) {
1936	    case BlockValidationResult::BLOCK_RESULT_UNSET:
1937	        break;
1938	    case BlockValidationResult::BLOCK_HEADER_LOW_WORK:
1939	        // We didn't try to process the block because the header chain may have
1940	        // too little work.
1941	        break;
1942	    // The node is providing invalid data:
1943	    case BlockValidationResult::BLOCK_CONSENSUS:
1944	    case BlockValidationResult::BLOCK_MUTATED:
1945	        if (!via_compact_block) {
1946	            if (peer) Misbehaving(*peer, message);
1947	            return;
1948	        }
1949	        break;
1950	    case BlockValidationResult::BLOCK_CACHED_INVALID:
1951	        {
1952	            // Discourage outbound (but not inbound) peers if on an invalid chain.
1953	            // Exempt HB compact block peers. Manual connections are always protected from discouragement.
1954	            if (peer && !via_compact_block && !peer->m_is_inbound) {
1955	                if (peer) Misbehaving(*peer, message);
1956	                return;
1957	            }
1958	            break;
1959	        }
1960	    case BlockValidationResult::BLOCK_INVALID_HEADER:
1961	    case BlockValidationResult::BLOCK_INVALID_PREV:
1962	        if (peer) Misbehaving(*peer, message);
1963	        return;
1964	    // Conflicting (but not necessarily invalid) data or different policy:
1965	    case BlockValidationResult::BLOCK_MISSING_PREV:
1966	        if (peer) Misbehaving(*peer, message);
1967	        return;
1968	    case BlockValidationResult::BLOCK_TIME_FUTURE:
1969	        break;
1970	    }
1971	    if (message != "") {
1972	        LogDebug(BCLog::NET, "peer=%d: %s\n", nodeid, message);
1973	    }
1974	}
