2524	CTransactionRef PeerManagerImpl::FindTxForGetData(const Peer::TxRelay& tx_relay, const GenTxid& gtxid)
2525	{
2526	    // If a tx was in the mempool prior to the last INV for this peer, permit the request.
2527	    auto txinfo{std::visit(
2528	        [&](const auto& id) {
2529	            return m_mempool.info_for_relay(id, WITH_LOCK(tx_relay.m_tx_inventory_mutex, return tx_relay.m_last_inv_sequence));
2530	        },
2531	        gtxid)};
2532	    if (txinfo.tx) {
2533	        return std::move(txinfo.tx);
2534	    }
2535	
2536	    // Or it might be from the most recent block
2537	    {
2538	        LOCK(m_most_recent_block_mutex);
2539	        if (m_most_recent_block_txs != nullptr) {
2540	            auto it = m_most_recent_block_txs->find(gtxid);
2541	            if (it != m_most_recent_block_txs->end()) return it->second;
2542	        }
2543	    }
2544	
2545	    return {};
2546	}
