2795	bool PeerManagerImpl::TryLowWorkHeadersSync(Peer& peer, CNode& pfrom, const CBlockIndex& chain_start_header, std::vector<CBlockHeader>& headers)
2796	{
2797	    // Calculate the claimed total work on this chain.
2798	    arith_uint256 total_work = chain_start_header.nChainWork + CalculateClaimedHeadersWork(headers);
2799	
2800	    // Our dynamic anti-DoS threshold (minimum work required on a headers chain
2801	    // before we'll store it)
2802	    arith_uint256 minimum_chain_work = GetAntiDoSWorkThreshold();
2803	
2804	    // Avoid DoS via low-difficulty-headers by only processing if the headers
2805	    // are part of a chain with sufficient work.
2806	    if (total_work < minimum_chain_work) {
2807	        // Only try to sync with this peer if their headers message was full;
2808	        // otherwise they don't have more headers after this so no point in
2809	        // trying to sync their too-little-work chain.
2810	        if (headers.size() == m_opts.max_headers_result) {
2811	            // Note: we could advance to the last header in this set that is
2812	            // known to us, rather than starting at the first header (which we
2813	            // may already have); however this is unlikely to matter much since
2814	            // ProcessHeadersMessage() already handles the case where all
2815	            // headers in a received message are already known and are
2816	            // ancestors of m_best_header or chainActive.Tip(), by skipping
2817	            // this logic in that case. So even if the first header in this set
2818	            // of headers is known, some header in this set must be new, so
2819	            // advancing to the first unknown header would be a small effect.
2820	            LOCK(peer.m_headers_sync_mutex);
2821	            peer.m_headers_sync.reset(new HeadersSyncState(peer.m_id, m_chainparams.GetConsensus(),
2822	                m_chainparams.HeadersSync(), chain_start_header, minimum_chain_work));
2823	
2824	            // Now a HeadersSyncState object for tracking this synchronization
2825	            // is created, process the headers using it as normal. Failures are
2826	            // handled inside of IsContinuationOfLowWorkHeadersSync.
2827	            (void)IsContinuationOfLowWorkHeadersSync(peer, pfrom, headers);
2828	        } else {
2829	            LogDebug(BCLog::NET, "Ignoring low-work chain (height=%u) from peer=%d\n", chain_start_header.nHeight + headers.size(), pfrom.GetId());
2830	        }
2831	
2832	        // The peer has not yet given us a chain that meets our work threshold,
2833	        // so we want to prevent further processing of the headers in any case.
2834	        headers = {};
2835	        return true;
2836	    }
2837	
2838	    return false;
2839	}
