6290	bool ChainstateManager::ValidatedSnapshotCleanup(Chainstate& validated_cs, Chainstate& unvalidated_cs)
6291	{
6292	    AssertLockHeld(::cs_main);
6293	    if (unvalidated_cs.m_assumeutxo != Assumeutxo::VALIDATED) {
6294	        // No need to clean up.
6295	        return false;
6296	    }
6297	
6298	    const fs::path validated_path{validated_cs.StoragePath()};
6299	    const fs::path assumed_valid_path{unvalidated_cs.StoragePath()};
6300	    const fs::path delete_path{validated_path + "_todelete"};
6301	
6302	    // Since we're going to be moving around the underlying leveldb filesystem content
6303	    // for each chainstate, make sure that the chainstates (and their constituent
6304	    // CoinsViews members) have been destructed first.
6305	    //
6306	    // The caller of this method will be responsible for reinitializing chainstates
6307	    // if they want to continue operation.
6308	    this->ResetChainstates();
6309	    assert(this->m_chainstates.size() == 0);
6310	
6311	    LogInfo("[snapshot] deleting background chainstate directory (now unnecessary) (%s)",
6312	              fs::PathToString(validated_path));
6313	
6314	    auto rename_failed_abort = [this](
6315	                                   fs::path p_old,
6316	                                   fs::path p_new,
6317	                                   const fs::filesystem_error& err) {
6318	        LogError("[snapshot] Error renaming path (%s) -> (%s): %s\n",
6319	                  fs::PathToString(p_old), fs::PathToString(p_new), err.what());
6320	        GetNotifications().fatalError(strprintf(_(
6321	            "Rename of '%s' -> '%s' failed. "
6322	            "Cannot clean up the background chainstate leveldb directory."),
6323	            fs::PathToString(p_old), fs::PathToString(p_new)));
6324	    };
6325	
6326	    try {
6327	        fs::rename(validated_path, delete_path);
6328	    } catch (const fs::filesystem_error& e) {
6329	        rename_failed_abort(validated_path, delete_path, e);
6330	        throw;
6331	    }
6332	
6333	    LogInfo("[snapshot] moving snapshot chainstate (%s) to "
6334	              "default chainstate directory (%s)",
6335	              fs::PathToString(assumed_valid_path), fs::PathToString(validated_path));
6336	
6337	    try {
6338	        fs::rename(assumed_valid_path, validated_path);
6339	    } catch (const fs::filesystem_error& e) {
6340	        rename_failed_abort(assumed_valid_path, validated_path, e);
6341	        throw;
6342	    }
6343	
6344	    if (!DeleteCoinsDBFromDisk(delete_path, /*is_snapshot=*/false)) {
6345	        // No need to FatalError because once the unneeded bg chainstate data is
6346	        // moved, it will not interfere with subsequent initialization.
6347	        LogWarning("Deletion of %s failed. Please remove it manually, as the "
6348	                   "directory is now unnecessary.",
6349	                   fs::PathToString(delete_path));
6350	    } else {
6351	        LogInfo("[snapshot] deleted background chainstate directory (%s)",
6352	                fs::PathToString(validated_path));
6353	    }
6354	    return true;
6355	}
