3528	bool Chainstate::InvalidateBlock(BlockValidationState& state, CBlockIndex* const pindex)
3529	{
3530	    AssertLockNotHeld(m_chainstate_mutex);
3531	    AssertLockNotHeld(::cs_main);
3532	
3533	    // Genesis block can't be invalidated
3534	    assert(pindex);
3535	    if (pindex->nHeight == 0) return false;
3536	
3537	    // We do not allow ActivateBestChain() to run while InvalidateBlock() is
3538	    // running, as that could cause the tip to change while we disconnect
3539	    // blocks.
3540	    LOCK(m_chainstate_mutex);
3541	
3542	    // We'll be acquiring and releasing cs_main below, to allow the validation
3543	    // callbacks to run. However, we should keep the block index in a
3544	    // consistent state as we disconnect blocks -- in particular we need to
3545	    // add equal-work blocks to setBlockIndexCandidates as we disconnect.
3546	    // To avoid walking the block index repeatedly in search of candidates,
3547	    // build a map once so that we can look up candidate blocks by chain
3548	    // work as we go.
3549	    std::multimap<const arith_uint256, CBlockIndex*> highpow_outofchain_headers;
3550	
3551	    {
3552	        LOCK(cs_main);
3553	        for (auto& entry : m_blockman.m_block_index) {
3554	            CBlockIndex& candidate = entry.second;
3555	            // We don't need to put anything in our active chain into the
3556	            // multimap, because those candidates will be found and considered
3557	            // as we disconnect.
3558	            // Instead, consider only non-active-chain blocks that score
3559	            // at least as good with CBlockIndexWorkComparator as the new tip.
3560	            if (!m_chain.Contains(candidate) &&
3561	                !CBlockIndexWorkComparator()(&candidate, pindex->pprev) &&
3562	                !(candidate.nStatus & BLOCK_FAILED_VALID)) {
3563	                highpow_outofchain_headers.insert({candidate.nChainWork, &candidate});
3564	            }
3565	        }
3566	    }
3567	
3568	    CBlockIndex* to_mark_failed = pindex;
3569	    bool pindex_was_in_chain = false;
3570	    int disconnected = 0;
3571	
3572	    // Disconnect (descendants of) pindex, and mark them invalid.
3573	    while (true) {
3574	        if (m_chainman.m_interrupt) break;
3575	
3576	        // Make sure the queue of validation callbacks doesn't grow unboundedly.
3577	        if (m_chainman.m_options.signals) LimitValidationInterfaceQueue(*m_chainman.m_options.signals);
3578	
3579	        LOCK(cs_main);
3580	        // Lock for as long as disconnectpool is in scope to make sure MaybeUpdateMempoolForReorg is
3581	        // called after DisconnectTip without unlocking in between
3582	        LOCK(MempoolMutex());
3583	        if (!m_chain.Contains(*pindex)) break;
3584	        pindex_was_in_chain = true;
3585	        CBlockIndex* const disconnected_tip{m_chain.Tip()};
3586	
3587	        // ActivateBestChain considers blocks already in m_chain
3588	        // unconditionally valid already, so force disconnect away from it.
3589	        DisconnectedBlockTransactions disconnectpool{MAX_DISCONNECTED_TX_POOL_BYTES};
3590	        bool ret = DisconnectTip(state, &disconnectpool);
3591	        // DisconnectTip will add transactions to disconnectpool.
3592	        // Adjust the mempool to be consistent with the new tip, adding
3593	        // transactions back to the mempool if disconnecting was successful,
3594	        // and we're not doing a very deep invalidation (in which case
3595	        // keeping the mempool up to date is probably futile anyway).
3596	        MaybeUpdateMempoolForReorg(disconnectpool, /* fAddToMempool = */ (++disconnected <= 10) && ret);
3597	        if (!ret) return false;
3598	        CBlockIndex* new_tip{m_chain.Tip()};
3599	        assert(disconnected_tip->pprev == new_tip);
3600	
3601	        // We immediately mark the disconnected blocks as invalid.
3602	        // This prevents a case where pruned nodes may fail to invalidateblock
3603	        // and be left unable to start as they have no tip candidates (as there
3604	        // are no blocks that meet the "have data and are not invalid per
3605	        // nStatus" criteria for inclusion in setBlockIndexCandidates).
3606	        disconnected_tip->nStatus |= BLOCK_FAILED_VALID;
3607	        m_blockman.m_dirty_blockindex.insert(disconnected_tip);
3608	        setBlockIndexCandidates.erase(disconnected_tip);
3609	        setBlockIndexCandidates.insert(new_tip);
3610	
3611	        // Mark out-of-chain descendants of the invalidated block as invalid
3612	        // Add any equal or more work headers that are not invalidated to setBlockIndexCandidates
3613	        // Recalculate m_best_header if it became invalid.
3614	        auto candidate_it = highpow_outofchain_headers.lower_bound(new_tip->nChainWork);
3615	
3616	        const bool best_header_needs_update{m_chainman.m_best_header->GetAncestor(disconnected_tip->nHeight) == disconnected_tip};
3617	        if (best_header_needs_update) {
3618	            // new_tip is definitely still valid at this point, but there may be better ones
3619	            m_chainman.m_best_header = new_tip;
3620	        }
3621	
3622	        while (candidate_it != highpow_outofchain_headers.end()) {
3623	            CBlockIndex* candidate{candidate_it->second};
3624	            if (candidate->GetAncestor(disconnected_tip->nHeight) == disconnected_tip) {
3625	                // Children of failed blocks are marked as BLOCK_FAILED_VALID.
3626	                candidate->nStatus |= BLOCK_FAILED_VALID;
3627	                m_blockman.m_dirty_blockindex.insert(candidate);
3628	                // If invalidated, the block is irrelevant for setBlockIndexCandidates
3629	                // and for m_best_header and can be removed from the cache.
3630	                candidate_it = highpow_outofchain_headers.erase(candidate_it);
3631	                continue;
3632	            }
3633	            if (!CBlockIndexWorkComparator()(candidate, new_tip) &&
3634	                candidate->IsValid(BLOCK_VALID_TRANSACTIONS) &&
3635	                candidate->HaveNumChainTxs()) {
3636	                setBlockIndexCandidates.insert(candidate);
3637	                // Do not remove candidate from the highpow_outofchain_headers cache, because it might be a descendant of the block being invalidated
3638	                // which needs to be marked failed later.
3639	            }
3640	            if (best_header_needs_update &&
3641	                m_chainman.m_best_header->nChainWork < candidate->nChainWork) {
3642	                m_chainman.m_best_header = candidate;
3643	            }
3644	            ++candidate_it;
3645	        }
3646	
3647	        // Track the last disconnected block to call InvalidChainFound on it.
3648	        to_mark_failed = disconnected_tip;
3649	    }
3650	
3651	    m_chainman.CheckBlockIndex();
3652	
3653	    {
3654	        LOCK(cs_main);
3655	        if (m_chain.Contains(*to_mark_failed)) {
3656	            // If the to-be-marked invalid block is in the active chain, something is interfering and we can't proceed.
3657	            return false;
3658	        }
3659	
3660	        // Mark pindex as invalid if it never was in the main chain
3661	        if (!pindex_was_in_chain && !(pindex->nStatus & BLOCK_FAILED_VALID)) {
3662	            pindex->nStatus |= BLOCK_FAILED_VALID;
3663	            m_blockman.m_dirty_blockindex.insert(pindex);
3664	            setBlockIndexCandidates.erase(pindex);
3665	        }
3666	
3667	        // If any new blocks somehow arrived while we were disconnecting
3668	        // (above), then the pre-calculation of what should go into
3669	        // setBlockIndexCandidates may have missed entries. This would
3670	        // technically be an inconsistency in the block index, but if we clean
3671	        // it up here, this should be an essentially unobservable error.
3672	        // Loop back over all block index entries and add any missing entries
3673	        // to setBlockIndexCandidates.
3674	        for (auto& [_, block_index] : m_blockman.m_block_index) {
3675	            if (block_index.IsValid(BLOCK_VALID_TRANSACTIONS) && block_index.HaveNumChainTxs() && !setBlockIndexCandidates.value_comp()(&block_index, m_chain.Tip())) {
3676	                setBlockIndexCandidates.insert(&block_index);
3677	            }
3678	        }
3679	
3680	        InvalidChainFound(to_mark_failed);
3681	    }
3682	
3683	    // Only notify about a new block tip if the active chain was modified.
3684	    if (pindex_was_in_chain) {
3685	        // Ignoring return value for now, this could be changed to bubble up
3686	        // kernel::Interrupted value to the caller so the caller could
3687	        // distinguish between completed and interrupted operations. It might
3688	        // also make sense for the blockTip notification to have an enum
3689	        // parameter indicating the source of the tip change so hooks can
3690	        // distinguish user-initiated invalidateblock changes from other
3691	        // changes.
3692	        (void)m_chainman.GetNotifications().blockTip(
3693	            /*state=*/GetSynchronizationState(m_chainman.IsInitialBlockDownload(), m_chainman.m_blockman.m_blockfiles_indexed),
3694	            /*index=*/*to_mark_failed->pprev,
3695	            /*verification_progress=*/WITH_LOCK(m_chainman.GetMutex(), return m_chainman.GuessVerificationProgress(to_mark_failed->pprev)));
3696	
3697	        // Fire ActiveTipChange now for the current chain tip to make sure clients are notified.
3698	        // ActivateBestChain may call this as well, but not necessarily.
3699	        if (m_chainman.m_options.signals) {
3700	            m_chainman.m_options.signals->ActiveTipChange(*Assert(m_chain.Tip()), m_chainman.IsInitialBlockDownload());
3701	        }
3702	    }
3703	    return true;
3704	}
