3718	void Chainstate::ResetBlockFailureFlags(CBlockIndex *pindex) {
3719	    AssertLockHeld(cs_main);
3720	
3721	    int nHeight = pindex->nHeight;
3722	
3723	    // Remove the invalidity flag from this block and all its descendants and ancestors.
3724	    for (auto& [_, block_index] : m_blockman.m_block_index) {
3725	        if ((block_index.nStatus & BLOCK_FAILED_VALID) && (block_index.GetAncestor(nHeight) == pindex || pindex->GetAncestor(block_index.nHeight) == &block_index)) {
3726	            block_index.nStatus &= ~BLOCK_FAILED_VALID;
3727	            m_blockman.m_dirty_blockindex.insert(&block_index);
3728	            if (block_index.IsValid(BLOCK_VALID_TRANSACTIONS) && block_index.HaveNumChainTxs() && setBlockIndexCandidates.value_comp()(m_chain.Tip(), &block_index)) {
3729	                setBlockIndexCandidates.insert(&block_index);
3730	            }
3731	            if (&block_index == m_chainman.m_best_invalid) {
3732	                // Reset invalid block marker if it was pointing to one of those.
3733	                m_chainman.m_best_invalid = nullptr;
3734	            }
3735	        }
3736	    }
3737	}
