3739	void Chainstate::TryAddBlockIndexCandidate(CBlockIndex* pindex)
3740	{
3741	    AssertLockHeld(cs_main);
3742	
3743	    // Do not continue building a chainstate that is based on an invalid
3744	    // snapshot. This is a belt-and-suspenders type of check because if an
3745	    // invalid snapshot is loaded, the node will shut down to force a manual
3746	    // intervention. But it is good to handle this case correctly regardless.
3747	    if (m_assumeutxo == Assumeutxo::INVALID) {
3748	        return;
3749	    }
3750	
3751	    // The block only is a candidate for the most-work-chain if it has the same
3752	    // or more work than our current tip.
3753	    if (m_chain.Tip() != nullptr && setBlockIndexCandidates.value_comp()(pindex, m_chain.Tip())) {
3754	        return;
3755	    }
3756	
3757	    const CBlockIndex* target_block{TargetBlock()};
3758	    if (!target_block) {
3759	        // If no specific target block, add all entries that have more
3760	        // work than the tip.
3761	        setBlockIndexCandidates.insert(pindex);
3762	    } else {
3763	        // If there is a target block, only consider connecting blocks
3764	        // towards the target block.
3765	        if (target_block->GetAncestor(pindex->nHeight) == pindex) {
3766	            setBlockIndexCandidates.insert(pindex);
3767	        }
3768	    }
3769	}
