3836	{
3837	    // Check proof of work matches claimed amount
3838	    if (fCheckPOW && !CheckProofOfWork(block.GetHash(), block.nBits, consensusParams))
3839	        return state.Invalid(BlockValidationResult::BLOCK_INVALID_HEADER, "high-hash", "proof of work failed");
