3843	
3844	static bool CheckMerkleRoot(const CBlock& block, BlockValidationState& state)
3845	{
3846	    if (block.m_checked_merkle_root) return true;
3847	
3848	    bool mutated;
3849	    uint256 merkle_root = BlockMerkleRoot(block, &mutated);
3850	    if (block.hashMerkleRoot != merkle_root) {
3851	        return state.Invalid(
3852	            /*result=*/BlockValidationResult::BLOCK_MUTATED,
3853	            /*reject_reason=*/"bad-txnmrklroot",
3854	            /*debug_message=*/"hashMerkleRoot mismatch");
3855	    }
3856	
3857	    // Check for merkle tree malleability (CVE-2012-2459): repeating sequences
3858	    // of transactions in a block without affecting the merkle root of a block,
3859	    // while still invalidating it.
3860	    if (mutated) {
3861	        return state.Invalid(
3862	            /*result=*/BlockValidationResult::BLOCK_MUTATED,
3863	            /*reject_reason=*/"bad-txns-duplicate",
3864	            /*debug_message=*/"duplicate transaction");
3865	    }
3866	
3867	    block.m_checked_merkle_root = true;
3868	    return true;
3869	}
3870	
3871	/** CheckWitnessMalleation performs checks for block malleation with regard to
3872	 * its witnesses.
3873	 *
3874	 * Note: If the witness commitment is expected (i.e. `expect_witness_commitment
3875	 * = true`), then the block is required to have at least one transaction and the
3876	 * first transaction needs to have at least one input. */
3877	static bool CheckWitnessMalleation(const CBlock& block, bool expect_witness_commitment, BlockValidationState& state)
3878	{
3879	    if (expect_witness_commitment) {
3880	        if (block.m_checked_witness_commitment) return true;
3881	
3882	        int commitpos = GetWitnessCommitmentIndex(block);
3883	        if (commitpos != NO_WITNESS_COMMITMENT) {
3884	            assert(!block.vtx.empty() && !block.vtx[0]->vin.empty());
3885	            const auto& witness_stack{block.vtx[0]->vin[0].scriptWitness.stack};
3886	
3887	            if (witness_stack.size() != 1 || witness_stack[0].size() != 32) {
3888	                return state.Invalid(
3889	                    /*result=*/BlockValidationResult::BLOCK_MUTATED,
3890	                    /*reject_reason=*/"bad-witness-nonce-size",
3891	                    /*debug_message=*/strprintf("%s : invalid witness reserved value size", __func__));
3892	            }
3893	
3894	            // The malleation check is ignored; as the transaction tree itself
3895	            // already does not permit it, it is impossible to trigger in the
3896	            // witness tree.
3897	            uint256 hash_witness = BlockWitnessMerkleRoot(block);
3898	
3899	            CHash256().Write(hash_witness).Write(witness_stack[0]).Finalize(hash_witness);
3900	            if (memcmp(hash_witness.begin(), &block.vtx[0]->vout[commitpos].scriptPubKey[6], 32)) {
3901	                return state.Invalid(
3902	                    /*result=*/BlockValidationResult::BLOCK_MUTATED,
3903	                    /*reject_reason=*/"bad-witness-merkle-match",
3904	                    /*debug_message=*/strprintf("%s : witness merkle commitment mismatch", __func__));
3905	            }
3906	
3907	            block.m_checked_witness_commitment = true;
3908	            return true;
3909	        }
3910	    }
3911	
3912	    // No witness data is allowed in blocks that don't commit to witness data, as this would otherwise leave room for spam
3913	    for (const auto& tx : block.vtx) {
3914	        if (tx->HasWitness()) {
3915	            return state.Invalid(
3916	                /*result=*/BlockValidationResult::BLOCK_MUTATED,
3917	                /*reject_reason=*/"unexpected-witness",
3918	                /*debug_message=*/strprintf("%s : unexpected witness data found", __func__));
3919	        }
3920	    }
3921	
3922	    return true;
3923	}
3924	
3925	bool CheckBlock(const CBlock& block, BlockValidationState& state, const Consensus::Params& consensusParams, bool fCheckPOW, bool fCheckMerkleRoot)
3926	{
3927	    // These are checks that are independent of context.
3928	
3929	    if (block.fChecked)
3930	        return true;
3931	
3932	    // Check that the header is valid (particularly PoW).  This is mostly
3933	    // redundant with the call in AcceptBlockHeader.
3934	    if (!CheckBlockHeader(block, state, consensusParams, fCheckPOW))
3935	        return false;
3936	
3937	    // Signet only: check block solution
3938	    if (consensusParams.signet_blocks && fCheckPOW && !CheckSignetBlockSolution(block, consensusParams)) {
3939	        return state.Invalid(BlockValidationResult::BLOCK_CONSENSUS, "bad-signet-blksig", "signet block signature validation failure");
3940	    }
3941	
3942	    // Check the merkle root.
3943	    if (fCheckMerkleRoot && !CheckMerkleRoot(block, state)) {
3944	        return false;
3945	    }
3946	
3947	    // All potential-corruption validation must be done before we do any
3948	    // transaction validation, as otherwise we may mark the header as invalid
3949	    // because we receive the wrong transactions for it.
3950	    // Note that witness malleability is checked in ContextualCheckBlock, so no
3951	    // checks that use witness data may be performed here.
3952	
3953	    // Size limits
3954	    if (block.vtx.empty() || block.vtx.size() * WITNESS_SCALE_FACTOR > MAX_BLOCK_WEIGHT || ::GetSerializeSize(TX_NO_WITNESS(block)) * WITNESS_SCALE_FACTOR > MAX_BLOCK_WEIGHT)
3955	        return state.Invalid(BlockValidationResult::BLOCK_CONSENSUS, "bad-blk-length", "size limits failed");
3956	
3957	    // First transaction must be coinbase, the rest must not be
3958	    if (block.vtx.empty() || !block.vtx[0]->IsCoinBase())
3959	        return state.Invalid(BlockValidationResult::BLOCK_CONSENSUS, "bad-cb-missing", "first tx is not coinbase");
3960	    for (unsigned int i = 1; i < block.vtx.size(); i++)
3961	        if (block.vtx[i]->IsCoinBase())
3962	            return state.Invalid(BlockValidationResult::BLOCK_CONSENSUS, "bad-cb-multiple", "more than one coinbase");
3963	
3964	    // Check transactions
3965	    // Must check for duplicate inputs (see CVE-2018-17144)
3966	    for (const auto& tx : block.vtx) {
3967	        TxValidationState tx_state;
3968	        if (!CheckTransaction(*tx, tx_state)) {
3969	            // CheckBlock() does context-free validation checks. The only
3970	            // possible failures are consensus failures.
3971	            assert(tx_state.GetResult() == TxValidationResult::TX_CONSENSUS);
3972	            return state.Invalid(BlockValidationResult::BLOCK_CONSENSUS, tx_state.GetRejectReason(),
3973	                                 strprintf("Transaction check failed (tx hash %s) %s", tx->GetHash().ToString(), tx_state.GetDebugMessage()));
3974	        }
3975	    }
3976	    // This underestimates the number of sigops, because unlike ConnectBlock it
3977	    // does not count witness and p2sh sigops.
3978	    unsigned int nSigOps = 0;
3979	    for (const auto& tx : block.vtx)
3980	    {
3981	        nSigOps += GetLegacySigOpCount(*tx);
3982	    }
3983	    if (nSigOps * WITNESS_SCALE_FACTOR > MAX_BLOCK_SIGOPS_COST)
3984	        return state.Invalid(BlockValidationResult::BLOCK_CONSENSUS, "bad-blk-sigops", "out-of-bounds SigOpCount");
3985	
3986	    if (fCheckPOW && fCheckMerkleRoot)
3987	        block.fChecked = true;
3988	
3989	    return true;
3990	}
