1642	    if (!IsWellFormedPackage(package, package_state_quit_early)) {
1643	        return PackageMempoolAcceptResult(package_state_quit_early, {});
1644	    }
1645	
1646	    if (package.size() > 1 && !IsChildWithParents(package)) {
