5965	
5966	// Currently, this function holds cs_main for its duration, which could be for
5967	// multiple minutes due to the ComputeUTXOStats call. Holding cs_main used to be
5968	// necessary (before d43a1f1a2fa3) to avoid advancing validated_cs farther than
5969	// its target block. Now it should be possible to avoid this, but simply
5970	// releasing cs_main here would not be possible because this function is invoked
5971	// by ConnectTip within ActivateBestChain.
5972	//
5973	// Eventually (TODO) it would be better to call this function outside of
5974	// ActivateBestChain, on a separate thread that should not require cs_main to
5975	// hash, because the UTXO set is only hashed after the historical chainstate
5976	// reaches its target block and is no longer changing.
5977	SnapshotCompletionResult ChainstateManager::MaybeValidateSnapshot(Chainstate& validated_cs, Chainstate& unvalidated_cs)
5978	{
5979	    AssertLockHeld(cs_main);
5980	
5981	    // If the snapshot does not need to be validated...
5982	    if (unvalidated_cs.m_assumeutxo != Assumeutxo::UNVALIDATED ||
5983	            // Or if either chainstate is unusable...
5984	            !unvalidated_cs.m_from_snapshot_blockhash ||
5985	            validated_cs.m_assumeutxo != Assumeutxo::VALIDATED ||
5986	            !validated_cs.m_chain.Tip() ||
5987	            // Or the validated chainstate is not targeting the snapshot block...
5988	            !validated_cs.m_target_blockhash ||
5989	            *validated_cs.m_target_blockhash != *unvalidated_cs.m_from_snapshot_blockhash ||
5990	            // Or the validated chainstate has not reached the snapshot block yet...
5991	            !validated_cs.ReachedTarget()) {
5992	       // Then the snapshot cannot be validated and there is nothing to do.
5993	       return SnapshotCompletionResult::SKIPPED;
5994	    }
5995	    assert(validated_cs.TargetBlock() == validated_cs.m_chain.Tip());
5996	
5997	    auto handle_invalid_snapshot = [&]() EXCLUSIVE_LOCKS_REQUIRED(::cs_main) {
5998	        bilingual_str user_error = strprintf(_(
5999	            "%s failed to validate the -assumeutxo snapshot state. "
6000	            "This indicates a hardware problem, or a bug in the software, or a "
6001	            "bad software modification that allowed an invalid snapshot to be "
6002	            "loaded. As a result of this, the node will shut down and stop using any "
6003	            "state that was built on the snapshot, resetting the chain height "
6004	            "from %d to %d. On the next "
6005	            "restart, the node will resume syncing from %d "
6006	            "without using any snapshot data. "
6007	            "Please report this incident to %s, including how you obtained the snapshot. "
6008	            "The invalid snapshot chainstate will be left on disk in case it is "
6009	            "helpful in diagnosing the issue that caused this error."),
6010	            CLIENT_NAME, unvalidated_cs.m_chain.Height(),
6011	            validated_cs.m_chain.Height(),
6012	            validated_cs.m_chain.Height(), CLIENT_BUGREPORT);
6013	
6014	        LogError("[snapshot] !!! %s\n", user_error.original);
6015	        LogError("[snapshot] deleting snapshot, reverting to validated chain, and stopping node\n");
6016	
6017	        // Reset chainstate target to network tip instead of snapshot block.
6018	        validated_cs.SetTargetBlock(nullptr);
6019	
6020	        unvalidated_cs.m_assumeutxo = Assumeutxo::INVALID;
6021	
6022	        auto rename_result = unvalidated_cs.InvalidateCoinsDBOnDisk();
6023	        if (!rename_result) {
6024	            user_error += Untranslated("\n") + util::ErrorString(rename_result);
6025	        }
6026	
6027	        GetNotifications().fatalError(user_error);
6028	    };
6029	
6030	    CCoinsViewDB& validated_coins_db = validated_cs.CoinsDB();
6031	    validated_cs.ForceFlushStateToDisk();
6032	
6033	    const auto& maybe_au_data = m_options.chainparams.AssumeutxoForHeight(validated_cs.m_chain.Height());
6034	    if (!maybe_au_data) {
6035	        LogWarning("[snapshot] assumeutxo data not found for height "
6036	            "(%d) - refusing to validate snapshot", validated_cs.m_chain.Height());
6037	        handle_invalid_snapshot();
6038	        return SnapshotCompletionResult::MISSING_CHAINPARAMS;
6039	    }
6040	
6041	    const AssumeutxoData& au_data = *maybe_au_data;
6042	    std::optional<CCoinsStats> validated_cs_stats;
6043	    LogInfo("[snapshot] computing UTXO stats for background chainstate to validate "
6044	        "snapshot - this could take a few minutes");
6045	    try {
6046	        validated_cs_stats = ComputeUTXOStats(
6047	            CoinStatsHashType::HASH_SERIALIZED,
6048	            &validated_coins_db,
6049	            m_blockman,
6050	            [&interrupt = m_interrupt] { SnapshotUTXOHashBreakpoint(interrupt); });
6051	    } catch (StopHashingException const&) {
6052	        return SnapshotCompletionResult::STATS_FAILED;
6053	    }
6054	
6055	    // XXX note that this function is slow and will hold cs_main for potentially minutes.
6056	    if (!validated_cs_stats) {
6057	        LogWarning("[snapshot] failed to generate stats for validation coins db");
6058	        // While this isn't a problem with the snapshot per se, this condition
6059	        // prevents us from validating the snapshot, so we should shut down and let the
6060	        // user handle the issue manually.
6061	        handle_invalid_snapshot();
6062	        return SnapshotCompletionResult::STATS_FAILED;
6063	    }
6064	
6065	    // Compare the validated chainstate's UTXO set hash against the hard-coded
6066	    // assumeutxo hash we expect.
6067	    //
6068	    // TODO: For belt-and-suspenders, we could cache the UTXO set
6069	    // hash for the snapshot when it's loaded in its chainstate's leveldb. We could then
6070	    // reference that here for an additional check.
6071	    if (AssumeutxoHash{validated_cs_stats->hashSerialized} != au_data.hash_serialized) {
6072	        LogWarning("[snapshot] hash mismatch: actual=%s, expected=%s",
6073	            validated_cs_stats->hashSerialized.ToString(),
6074	            au_data.hash_serialized.ToString());
6075	        handle_invalid_snapshot();
6076	        return SnapshotCompletionResult::HASH_MISMATCH;
6077	    }
6078	
6079	    LogInfo("[snapshot] snapshot beginning at %s has been fully validated",
6080	        unvalidated_cs.m_from_snapshot_blockhash->ToString());
6081	
6082	    unvalidated_cs.m_assumeutxo = Assumeutxo::VALIDATED;
6083	    validated_cs.m_target_utxohash = AssumeutxoHash{validated_cs_stats->hashSerialized};
6084	    this->MaybeRebalanceCaches();
6085	
6086	    return SnapshotCompletionResult::SUCCESS;
6087	}
