6104	    } else if (!historical_cs) {
6105	        // If background validation has completed and snapshot is our active chain...
6106	        LogInfo("[snapshot] allocating all cache to the snapshot chainstate");
6107	        // Allocate everything to the snapshot chainstate.
6108	        current_cs.ResizeCoinsCaches(m_total_coinstip_cache, m_total_coinsdb_cache);
6109	    } else {
6110	        // If both chainstates exist, determine who needs more cache based on IBD status.
6111	        //
6112	        // Note: shrink caches first so that we don't inadvertently overwhelm available memory.
6113	        if (IsInitialBlockDownload()) {
6114	            historical_cs->ResizeCoinsCaches(
6115	                m_total_coinstip_cache * 0.05, m_total_coinsdb_cache * 0.05);
6116	            current_cs.ResizeCoinsCaches(
6117	                m_total_coinstip_cache * 0.95, m_total_coinsdb_cache * 0.95);
6118	        } else {
