5598	util::Result<CBlockIndex*> ChainstateManager::ActivateSnapshot(
5599	        AutoFile& coins_file,
5600	        const SnapshotMetadata& metadata,
5601	        bool in_memory)
5602	{
5603	    uint256 base_blockhash = metadata.m_base_blockhash;
5604	
5605	    CBlockIndex* snapshot_start_block{};
5606	
5607	    {
5608	        LOCK(::cs_main);
5609	
5610	        if (this->CurrentChainstate().m_from_snapshot_blockhash) {
5611	            return util::Error{Untranslated("Can't activate a snapshot-based chainstate more than once")};
5612	        }
5613	        if (!GetParams().AssumeutxoForBlockhash(base_blockhash).has_value()) {
5614	            auto available_heights = GetParams().GetAvailableSnapshotHeights();
5615	            std::string heights_formatted = util::Join(available_heights, ", ", [&](const auto& i) { return util::ToString(i); });
5616	            return util::Error{Untranslated(strprintf("assumeutxo block hash in snapshot metadata not recognized (hash: %s). The following snapshot heights are available: %s",
5617	                base_blockhash.ToString(),
5618	                heights_formatted))};
5619	        }
5620	
5621	        snapshot_start_block = m_blockman.LookupBlockIndex(base_blockhash);
5622	        if (!snapshot_start_block) {
5623	            return util::Error{Untranslated(strprintf("The base block header (%s) must appear in the headers chain. Make sure all headers are syncing, and call loadtxoutset again",
5624	                          base_blockhash.ToString()))};
5625	        }
5626	
5627	        bool start_block_invalid = snapshot_start_block->nStatus & BLOCK_FAILED_VALID;
5628	        if (start_block_invalid) {
