5630	        }
5631	
5632	        if (!m_best_header || m_best_header->GetAncestor(snapshot_start_block->nHeight) != snapshot_start_block) {
5633	            return util::Error{Untranslated("A forked headers-chain with more work than the chain with the snapshot base block header exists. Please proceed to sync without AssumeUtxo.")};
5634	        }
5635	
5636	        auto mempool{CurrentChainstate().GetMempool()};
5637	        if (mempool && mempool->size() > 0) {
5638	            return util::Error{Untranslated("Can't activate a snapshot when mempool not empty")};
5639	        }
5640	    }
5641	
5642	    int64_t current_coinsdb_cache_size{0};
5643	    int64_t current_coinstip_cache_size{0};
5644	
5645	    // Cache percentages to allocate to each chainstate.
5646	    //
5647	    // These particular percentages don't matter so much since they will only be
5648	    // relevant during snapshot activation; caches are rebalanced at the conclusion of
5649	    // this function. We want to give (essentially) all available cache capacity to the
5650	    // snapshot to aid the bulk load later in this function.
5651	    static constexpr double IBD_CACHE_PERC = 0.01;
5652	    static constexpr double SNAPSHOT_CACHE_PERC = 0.99;
5653	
5654	    {
5655	        LOCK(::cs_main);
5656	        // Resize the coins caches to ensure we're not exceeding memory limits.
5657	        //
5658	        // Allocate the majority of the cache to the incoming snapshot chainstate, since
5659	        // (optimistically) getting to its tip will be the top priority. We'll need to call
5660	        // `MaybeRebalanceCaches()` once we're done with this function to ensure
5661	        // the right allocation (including the possibility that no snapshot was activated
5662	        // and that we should restore the active chainstate caches to their original size).
5663	        //
5664	        current_coinsdb_cache_size = this->ActiveChainstate().m_coinsdb_cache_size_bytes;
5665	        current_coinstip_cache_size = this->ActiveChainstate().m_coinstip_cache_size_bytes;
5666	
5667	        // Temporarily resize the active coins cache to make room for the newly-created
5668	        // snapshot chain.
5669	        this->ActiveChainstate().ResizeCoinsCaches(
5670	            static_cast<size_t>(current_coinstip_cache_size * IBD_CACHE_PERC),
5671	            static_cast<size_t>(current_coinsdb_cache_size * IBD_CACHE_PERC));
5672	    }
5673	
5674	    auto snapshot_chainstate = WITH_LOCK(::cs_main,
5675	        return std::make_unique<Chainstate>(
5676	            /*mempool=*/nullptr, m_blockman, *this, base_blockhash));
5677	
5678	    {
5679	        LOCK(::cs_main);
5680	        snapshot_chainstate->InitCoinsDB(
5681	            static_cast<size_t>(current_coinsdb_cache_size * SNAPSHOT_CACHE_PERC),
5682	            in_memory, /*should_wipe=*/false);
5683	        snapshot_chainstate->InitCoinsCache(
5684	            static_cast<size_t>(current_coinstip_cache_size * SNAPSHOT_CACHE_PERC));
5685	    }
5686	
5687	    auto cleanup_bad_snapshot = [&](bilingual_str reason) EXCLUSIVE_LOCKS_REQUIRED(::cs_main) {
5688	        this->MaybeRebalanceCaches();
5689	
5690	        // PopulateAndValidateSnapshot can return (in error) before the leveldb datadir
5691	        // has been created, so only attempt removal if we got that far.
5692	        if (auto snapshot_datadir = node::FindAssumeutxoChainstateDir(m_options.datadir)) {
5693	            // We have to destruct leveldb::DB in order to release the db lock, otherwise
5694	            // DestroyDB() (in DeleteCoinsDBFromDisk()) will fail. See `leveldb::~DBImpl()`.
5695	            // Destructing the chainstate (and so resetting the coinsviews object) does this.
5696	            snapshot_chainstate.reset();
5697	            bool removed = DeleteCoinsDBFromDisk(*snapshot_datadir, /*is_snapshot=*/true);
5698	            if (!removed) {
5699	                GetNotifications().fatalError(strprintf(_("Failed to remove snapshot chainstate dir (%s). "
5700	                    "Manually remove it before restarting.\n"), fs::PathToString(*snapshot_datadir)));
5701	            }
5702	        }
5703	        return util::Error{std::move(reason)};
5704	    };
5705	
5706	    if (auto res{this->PopulateAndValidateSnapshot(*snapshot_chainstate, coins_file, metadata)}; !res) {
5707	        LOCK(::cs_main);
5708	        return cleanup_bad_snapshot(Untranslated(strprintf("Population failed: %s", util::ErrorString(res).original)));
5709	    }
5710	
5711	    LOCK(::cs_main);  // cs_main required for rest of snapshot activation.
5712	
5713	    // Do a final check to ensure that the snapshot chainstate is actually a more
5714	    // work chain than the active chainstate; a user could have loaded a snapshot
5715	    // very late in the IBD process, and we wouldn't want to load a useless chainstate.
5716	    if (!CBlockIndexWorkComparator()(ActiveTip(), snapshot_chainstate->m_chain.Tip())) {
5717	        return cleanup_bad_snapshot(Untranslated("work does not exceed active chainstate"));
5718	    }
5719	    // If not in-memory, persist the base blockhash for use during subsequent
5720	    // initialization.
5721	    if (!in_memory) {
5722	        if (!node::WriteSnapshotBaseBlockhash(*snapshot_chainstate)) {
5723	            return cleanup_bad_snapshot(Untranslated("could not write base blockhash"));
5724	        }
5725	    }
5726	
5727	    Chainstate& chainstate{AddChainstate(std::move(snapshot_chainstate))};
5728	    m_blockman.m_snapshot_height = Assert(chainstate.SnapshotBase())->nHeight;
5729	
5730	    chainstate.PopulateBlockIndexCandidates();
5731	
5732	    LogInfo("[snapshot] successfully activated snapshot %s", base_blockhash.ToString());
5733	    LogInfo("[snapshot] (%.2f MB)",
5734	              chainstate.CoinsTip().DynamicMemoryUsage() / (1000 * 1000));
5735	
5736	    this->MaybeRebalanceCaches();
5737	    return snapshot_start_block;
5738	}
