5085	                NotifyHeaderTip();
5086	
5087	                if (!blocks_with_unknown_parent) continue;
5088	
5089	                // Recursively process earlier encountered successors of this block
5090	                std::deque<uint256> queue;
5091	                queue.push_back(hash);
5092	                while (!queue.empty()) {
5093	                    uint256 head = queue.front();
5094	                    queue.pop_front();
5095	                    auto range = blocks_with_unknown_parent->equal_range(head);
5096	                    while (range.first != range.second) {
5097	                        std::multimap<uint256, FlatFilePos>::iterator it = range.first;
5098	                        std::shared_ptr<CBlock> pblockrecursive = std::make_shared<CBlock>();
5099	                        if (m_blockman.ReadBlock(*pblockrecursive, it->second, {})) {
5100	                            const auto& block_hash{pblockrecursive->GetHash()};
5101	                            LogDebug(BCLog::REINDEX, "%s: Processing out of order child %s of %s", __func__, block_hash.ToString(), head.ToString());
5102	                            LOCK(cs_main);
5103	                            BlockValidationState dummy;
5104	                            if (AcceptBlock(pblockrecursive, dummy, nullptr, true, &it->second, nullptr, true)) {
5105	                                nLoaded++;
5106	                                queue.push_back(block_hash);
5107	                            }
5108	                        }
5109	                        range.first++;
5110	                        blocks_with_unknown_parent->erase(it);
5111	                        NotifyHeaderTip();
5112	                    }
5113	                }
5114	            } catch (const std::exception& e) {
5115	                // historical bugs added extra data to the block files that does not deserialize cleanly.
5116	                // commonly this data is between readable blocks, but it does not really matter. such data is not fatal to the import process.
5117	                // the code that reads the block files deals with invalid data by simply ignoring it.
5118	                // it continues to search for the next {4 byte magic message start bytes + 4 byte length + block} that does deserialize cleanly
5119	                // and passes all of the other block validation checks dealing with POW and the merkle root, etc...
5120	                // we merely note with this informational log message when unexpected data is encountered.
5121	                // we could also be experiencing a storage system read error, or a read of a previous bad write. these are possible, but
5122	                // less likely scenarios. we don't have enough information to tell a difference here.
5123	                // the reindex process is not the place to attempt to clean and/or compact the block files. if so desired, a studious node operator
5124	                // may use knowledge of the fact that the block files are not entirely pristine in order to prepare a set of pristine, and
5125	                // perhaps ordered, block files for later reindexing.
5126	                LogDebug(BCLog::REINDEX, "%s: unexpected data at file offset 0x%x - %s. continuing\n", __func__, (nRewind - 1), e.what());
5127	            }
5128	        }
5129	    } catch (const std::runtime_error& e) {
5130	        GetNotifications().fatalError(strprintf(_("System error while loading external block file: %s"), e.what()));
5131	    }
5132	    LogInfo("Loaded %i blocks from external file in %dms", nLoaded, Ticks<std::chrono::milliseconds>(SteadyClock::now() - start));
5133	}
