4910	bool ChainstateManager::LoadBlockIndex()
4911	{
4912	    AssertLockHeld(cs_main);
4913	    // Load block index from databases
4914	    if (m_blockman.m_blockfiles_indexed) {
4915	        bool ret{m_blockman.LoadBlockIndexDB(CurrentChainstate().m_from_snapshot_blockhash)};
4916	        if (!ret) return false;
4917	
4918	        m_blockman.ScanAndUnlinkAlreadyPrunedFiles();
4919	
4920	        std::vector<CBlockIndex*> vSortedByHeight{m_blockman.GetAllBlockIndices()};
4921	        std::sort(vSortedByHeight.begin(), vSortedByHeight.end(),
4922	                  CBlockIndexHeightOnlyComparator());
4923	
4924	        for (CBlockIndex* pindex : vSortedByHeight) {
4925	            if (m_interrupt) return false;
4926	            if (pindex->nStatus & BLOCK_FAILED_VALID && (!m_best_invalid || pindex->nChainWork > m_best_invalid->nChainWork)) {
4927	                m_best_invalid = pindex;
4928	            }
4929	            if (pindex->IsValid(BLOCK_VALID_TREE) && (m_best_header == nullptr || CBlockIndexWorkComparator()(m_best_header, pindex)))
4930	                m_best_header = pindex;
4931	        }
4932	    }
4933	    return true;
4934	}
