6180	Chainstate& ChainstateManager::AddChainstate(std::unique_ptr<Chainstate> chainstate)
6181	{
6182	    Chainstate& prev_chainstate{CurrentChainstate()};
6183	    assert(prev_chainstate.m_assumeutxo == Assumeutxo::VALIDATED);
6184	    // Set target block for historical chainstate to snapshot block.
6185	    assert(!prev_chainstate.m_target_blockhash);
6186	    prev_chainstate.m_target_blockhash = chainstate->m_from_snapshot_blockhash;
6187	    m_chainstates.push_back(std::move(chainstate));
6188	    Chainstate& curr_chainstate{CurrentChainstate()};
6189	    assert(&curr_chainstate == m_chainstates.back().get());
6190	
6191	    // Transfer possession of the mempool to the chainstate.
6192	    // Mempool is empty at this point because we're still in IBD.
6193	    assert(!prev_chainstate.m_mempool || prev_chainstate.m_mempool->size() == 0);
6194	    assert(!curr_chainstate.m_mempool);
6195	    std::swap(curr_chainstate.m_mempool, prev_chainstate.m_mempool);
6196	    return curr_chainstate;
6197	}
