6211	util::Result<void> Chainstate::InvalidateCoinsDBOnDisk()
6212	{
6213	    // Should never be called on a non-snapshot chainstate.
6214	    assert(m_from_snapshot_blockhash);
6215	
6216	    // Coins views no longer usable.
6217	    m_coins_views.reset();
6218	
6219	    const fs::path db_path{StoragePath()};
6220	    const fs::path invalid_path{db_path + "_INVALID"};
6221	    const std::string db_path_str{fs::PathToString(db_path)};
6222	    const std::string invalid_path_str{fs::PathToString(invalid_path)};
6223	    LogInfo("[snapshot] renaming snapshot datadir %s to %s", db_path_str, invalid_path_str);
6224	
6225	    // The invalid storage directory is simply moved and not deleted because we may
6226	    // want to do forensics later during issue investigation. The user is instructed
6227	    // accordingly in MaybeValidateSnapshot().
6228	    try {
6229	        fs::rename(db_path, invalid_path);
6230	    } catch (const fs::filesystem_error& e) {
6231	        LogError("While invalidating the coins db: Error renaming file '%s' -> '%s': %s",
6232	                 db_path_str, invalid_path_str, e.what());
6233	        return util::Error{strprintf(_(
6234	            "Rename of '%s' -> '%s' failed. "
6235	            "You should resolve this by manually moving or deleting the invalid "
6236	            "snapshot directory %s, otherwise you will encounter the same error again "
6237	            "on the next startup."),
6238	            db_path_str, invalid_path_str, db_path_str)};
6239	    }
6240	    return {};
6241	}
