6278	{
6279	    LOCK(::cs_main);
6280	    const CBlockIndex* best_header{m_best_header};
6281	    const CBlockIndex* tip{ActiveChain().Tip()};
6282	    // Only consider headers that extend the active tip; ignore competing branches.
6283	    if (best_header && tip && best_header->nChainWork > tip->nChainWork &&
6284	        best_header->GetAncestor(tip->nHeight) == tip) {
6285	        return best_header->nHeight - tip->nHeight;
