4304	/** Store block on disk. If dbp is non-nullptr, the file is known to already reside on disk */
4305	bool ChainstateManager::AcceptBlock(const std::shared_ptr<const CBlock>& pblock, BlockValidationState& state, CBlockIndex** ppindex, bool fRequested, const FlatFilePos* dbp, bool* fNewBlock, bool min_pow_checked)
4306	{
4307	    const CBlock& block = *pblock;
4308	
4309	    if (fNewBlock) *fNewBlock = false;
4310	    AssertLockHeld(cs_main);
4311	
4312	    CBlockIndex *pindexDummy = nullptr;
4313	    CBlockIndex *&pindex = ppindex ? *ppindex : pindexDummy;
4314	
4315	    bool accepted_header{AcceptBlockHeader(block, state, &pindex, min_pow_checked)};
4316	    CheckBlockIndex();
4317	
4318	    if (!accepted_header)
4319	        return false;
4320	
4321	    // Check all requested blocks that we do not already have for validity and
4322	    // save them to disk. Skip processing of unrequested blocks as an anti-DoS
4323	    // measure, unless the blocks have more work than the active chain tip, and
4324	    // aren't too far ahead of it, so are likely to be attached soon.
4325	    bool fAlreadyHave = pindex->nStatus & BLOCK_HAVE_DATA;
4326	    bool fHasMoreOrSameWork = (ActiveTip() ? pindex->nChainWork >= ActiveTip()->nChainWork : true);
4327	    // Blocks that are too out-of-order needlessly limit the effectiveness of
4328	    // pruning, because pruning will not delete block files that contain any
4329	    // blocks which are too close in height to the tip.  Apply this test
4330	    // regardless of whether pruning is enabled; it should generally be safe to
4331	    // not process unrequested blocks.
4332	    bool fTooFarAhead{pindex->nHeight > ActiveHeight() + int(MIN_BLOCKS_TO_KEEP)};
4333	
4334	    // TODO: Decouple this function from the block download logic by removing fRequested
4335	    // This requires some new chain data structure to efficiently look up if a
4336	    // block is in a chain leading to a candidate for best tip, despite not
4337	    // being such a candidate itself.
4338	    // Note that this would break the getblockfrompeer RPC
4339	
4340	    // TODO: deal better with return value and error conditions for duplicate
4341	    // and unrequested blocks.
4342	    if (fAlreadyHave) return true;
4343	    if (!fRequested) {  // If we didn't ask for it:
4344	        if (pindex->nTx != 0) return true;    // This is a previously-processed block that was pruned
4345	        if (!fHasMoreOrSameWork) return true; // Don't process less-work chains
4346	        if (fTooFarAhead) return true;        // Block height is too high
4347	
4348	        // Protect against DoS attacks from low-work chains.
4349	        // If our tip is behind, a peer could try to send us
4350	        // low-work blocks on a fake chain that we would never
4351	        // request; don't process these.
4352	        if (pindex->nChainWork < MinimumChainWork()) return true;
4353	    }
4354	
4355	    const CChainParams& params{GetParams()};
4356	
4357	    if (!CheckBlock(block, state, params.GetConsensus()) ||
4358	        !ContextualCheckBlock(block, state, *this, pindex->pprev)) {
4359	        if (Assume(state.IsInvalid())) {
4360	            ActiveChainstate().InvalidBlockFound(pindex, state);
4361	        }
4362	        LogError("%s: %s\n", __func__, state.ToString());
4363	        return false;
4364	    }
4365	
4366	    // Header is valid/has work, merkle tree and segwit merkle tree are good...RELAY NOW
4367	    // (but if it does not build on our best tip, let the SendMessages loop relay it)
4368	    if (!IsInitialBlockDownload() && ActiveTip() == pindex->pprev && m_options.signals) {
4369	        m_options.signals->NewPoWValidBlock(pindex, pblock);
4370	    }
4371	
4372	    // Write block to history file
4373	    if (fNewBlock) *fNewBlock = true;
4374	    try {
4375	        FlatFilePos blockPos{};
4376	        if (dbp) {
4377	            blockPos = *dbp;
4378	            m_blockman.UpdateBlockInfo(block, pindex->nHeight, blockPos);
4379	        } else {
4380	            blockPos = m_blockman.WriteBlock(block, pindex->nHeight);
4381	            if (blockPos.IsNull()) {
4382	                state.Error(strprintf("%s: Failed to find position to write new block to disk", __func__));
4383	                return false;
4384	            }
4385	        }
4386	        ReceivedBlockTransactions(block, pindex, blockPos);
4387	    } catch (const std::runtime_error& e) {
4388	        return FatalError(GetNotifications(), state, strprintf(_("System error while saving block to disk: %s"), e.what()));
4389	    }
4390	
4391	    // TODO: FlushStateToDisk() handles flushing of both block and chainstate
4392	    // data, so we should move this to ChainstateManager so that we can be more
4393	    // intelligent about how we flush.
4394	    // For now, since FlushStateMode::NONE is used, all that can happen is that
4395	    // the block files may be pruned, so we can just call this on one
4396	    // chainstate (particularly if we haven't implemented pruning with
4397	    // background validation yet).
4398	    ActiveChainstate().FlushStateToDisk(state, FlushStateMode::NONE);
4399	
4400	    CheckBlockIndex();
4401	
4402	    return true;
4403	}
