4405	bool ChainstateManager::ProcessNewBlock(const std::shared_ptr<const CBlock>& block, bool force_processing, bool min_pow_checked, bool* new_block)
4406	{
4407	    AssertLockNotHeld(cs_main);
4408	
4409	    {
4410	        CBlockIndex *pindex = nullptr;
4411	        if (new_block) *new_block = false;
4412	        BlockValidationState state;
4413	
4414	        // CheckBlock() does not support multi-threaded block validation because CBlock::fChecked can cause data race.
4415	        // Therefore, the following critical section must include the CheckBlock() call as well.
4416	        LOCK(cs_main);
4417	
4418	        // Skipping AcceptBlock() for CheckBlock() failures means that we will never mark a block as invalid if
4419	        // CheckBlock() fails.  This is protective against consensus failure if there are any unknown forms of block
4420	        // malleability that cause CheckBlock() to fail; see e.g. CVE-2012-2459 and
4421	        // https://lists.linuxfoundation.org/pipermail/bitcoin-dev/2019-February/016697.html.  Because CheckBlock() is
4422	        // not very expensive, the anti-DoS benefits of caching failure (of a definitely-invalid block) are not substantial.
4423	        bool ret = CheckBlock(*block, state, GetConsensus());
4424	        if (ret) {
4425	            // Store to disk
4426	            ret = AcceptBlock(block, state, &pindex, force_processing, nullptr, new_block, min_pow_checked);
4427	        }
4428	        if (!ret) {
4429	            if (m_options.signals) {
4430	                m_options.signals->BlockChecked(block, state);
4431	            }
4432	            LogError("%s: AcceptBlock FAILED (%s)\n", __func__, state.ToString());
4433	            return false;
4434	        }
4435	    }
4436	
4437	    NotifyHeaderTip();
4438	
4439	    BlockValidationState state; // Only used to report errors, not invalidity - ignore it
4440	    if (!ActiveChainstate().ActivateBestChain(state, block)) {
4441	        LogError("%s: ActivateBestChain failed (%s)\n", __func__, state.ToString());
4442	        return false;
4443	    }
4444	
4445	    Chainstate* bg_chain{WITH_LOCK(cs_main, return HistoricalChainstate())};
4446	    BlockValidationState bg_state;
4447	    if (bg_chain && !bg_chain->ActivateBestChain(bg_state, block)) {
4448	        LogError("%s: [background] ActivateBestChain failed (%s)\n", __func__, bg_state.ToString());
4449	        return false;

4500	     * instead:
4501	     * - skip AcceptBlockHeader() because:
4502	     *   - we don't want to update the block index
4503	     *   - we do not care about duplicates
4504	     *   - we already ran CheckBlockHeader() via CheckBlock()
4505	     *   - we already checked for prev-blk-not-found
4506	     *   - we know the tip is valid, so no need to check bad-prevblk
4507	     * - we already ran CheckBlock()
4508	     * - do run ContextualCheckBlockHeader()
4509	     * - do run ContextualCheckBlock()
4510	     */
4511	
4512	    if (!ContextualCheckBlockHeader(block, state, chainstate.m_chainman, tip)) {
4513	        if (state.IsValid()) NONFATAL_UNREACHABLE();
4514	        return state;
4515	    }
4516	
4517	    if (!ContextualCheckBlock(block, state, chainstate.m_chainman, tip)) {
4518	        if (state.IsValid()) NONFATAL_UNREACHABLE();
4519	        return state;
4520	    }
4521	
4522	    // We don't want ConnectBlock to update the actual chainstate, so create
4523	    // a cache on top of it, along with a dummy block index.
4524	    CBlockIndex index_dummy{block};
4525	    uint256 block_hash(block.GetHash());
4526	    index_dummy.pprev = tip;
4527	    index_dummy.nHeight = tip->nHeight + 1;
4528	    index_dummy.phashBlock = &block_hash;
4529	    CCoinsViewCache view_dummy(&chainstate.CoinsTip());
4530	
4531	    // Set fJustCheck to true in order to update, and not clear, validation caches.
4532	    if(!chainstate.ConnectBlock(block, state, &index_dummy, view_dummy, /*fJustCheck=*/true)) {
4533	        if (state.IsValid()) NONFATAL_UNREACHABLE();
4534	        return state;
4535	    }
4536	
4537	    // Ensure no check returned successfully while also setting an invalid state.
4538	    if (!state.IsValid()) NONFATAL_UNREACHABLE();
4539	
4540	    return state;
4541	}
