4553	bool Chainstate::LoadChainTip()
4554	{
4555	    AssertLockHeld(cs_main);
4556	    const CCoinsViewCache& coins_cache = CoinsTip();
4557	    assert(!coins_cache.GetBestBlock().IsNull()); // Never called when the coins view is empty
4558	    CBlockIndex* tip = m_chain.Tip();
4559	
4560	    if (tip && tip->GetBlockHash() == coins_cache.GetBestBlock()) {
4561	        return true;
4562	    }
4563	
4564	    // Load pointer to end of best chain
4565	    CBlockIndex* pindex = m_blockman.LookupBlockIndex(coins_cache.GetBestBlock());
4566	    if (!pindex) {
4567	        return false;
4568	    }
4569	    m_chain.SetTip(*pindex);
4570	    m_chainman.UpdateIBDStatus();
4571	    tip = m_chain.Tip();
4572	
4573	    // nSequenceId is one of the keys used to sort setBlockIndexCandidates. Ensure all
4574	    // candidate sets are empty to avoid UB, as nSequenceId is about to be modified.
4575	    for (const auto& cs : m_chainman.m_chainstates) {
4576	        assert(cs->setBlockIndexCandidates.empty());
4577	    }
4578	
4579	    // Make sure our chain tip before shutting down scores better than any other candidate
4580	    // to maintain a consistent best tip over reboots in case of a tie.
4581	    auto target = tip;
4582	    while (target) {
4583	        target->nSequenceId = SEQ_ID_BEST_CHAIN_FROM_DISK;
4584	        target = target->pprev;
4585	    }
4586	
4587	    LogInfo("Loaded best chain: hashBestChain=%s height=%d date=%s progress=%f",
4588	              tip->GetBlockHash().ToString(),
4589	              m_chain.Height(),
4590	              FormatISO8601DateTime(tip->GetBlockTime()),
4591	              m_chainman.GuessVerificationProgress(tip));
4592	
4593	    // Ensure KernelNotifications m_tip_block is set even if no new block arrives.
4594	    if (!this->GetRole().historical) {
4595	        // Ignoring return value for now.
4596	        (void)m_chainman.GetNotifications().blockTip(
4597	            /*state=*/GetSynchronizationState(/*init=*/true, m_chainman.m_blockman.m_blockfiles_indexed),
4598	            /*index=*/*pindex,
4599	            /*verification_progress=*/m_chainman.GuessVerificationProgress(tip));
4600	    }
4601	
4602	    CheckForkWarningConditions();
4603	
4604	    return true;
4605	}
