4618	VerifyDBResult CVerifyDB::VerifyDB(
4619	    Chainstate& chainstate,
4620	    const Consensus::Params& consensus_params,
4621	    CCoinsView& coinsview,
4622	    int nCheckLevel, int nCheckDepth)
4623	{
4624	    AssertLockHeld(cs_main);
4625	
4626	    if (chainstate.m_chain.Tip() == nullptr || chainstate.m_chain.Tip()->pprev == nullptr) {
4627	        return VerifyDBResult::SUCCESS;
4628	    }
4629	
4630	    // Verify blocks in the best chain
4631	    if (nCheckDepth <= 0 || nCheckDepth > chainstate.m_chain.Height()) {
4632	        nCheckDepth = chainstate.m_chain.Height();
4633	    }
4634	    nCheckLevel = std::max(0, std::min(4, nCheckLevel));
4635	    LogInfo("Verifying last %i blocks at level %i", nCheckDepth, nCheckLevel);
4636	    CCoinsViewCache coins(&coinsview);
4637	    CBlockIndex* pindex;
