97	bool EvaluateSequenceLocks(const CBlockIndex& block, std::pair<int, int64_t> lockPair)
98	{
99	    assert(block.pprev);
100	    int64_t nBlockTime = block.pprev->GetMedianTimePast();
101	    if (lockPair.first >= block.nHeight || lockPair.second >= nBlockTime)
102	        return false;
103	
104	    return true;
105	}
