107	bool SequenceLocks(const CTransaction &tx, int flags, std::vector<int>& prevHeights, const CBlockIndex& block)
108	{
109	    return EvaluateSequenceLocks(block, CalculateSequenceLocks(tx, flags, prevHeights, block));
